function autoTarget(a){const enemyTeam=a.team==="blue"?"red":"blue",enemies=living(enemyTeam),soldiers=enemies.filter(e=>e.kind==="soldier"),structures=structureTargets(enemyTeam);let pool=soldiers.length?soldiers:structures;if(!pool.length)return null;if(a.kind==="soldier"&&!soldiers.length){pool.sort((x,y)=>dist(a,x)-dist(a,y));return pool[0]}if(a.team===game.aiTeam&&Math.random()>levels[game.difficulty].aim)return pool[Math.floor(Math.random()*pool.length)];pool.sort((x,y)=>{const damaged=x.hp/x.maxHp-y.hp/y.maxHp;return Math.abs(damaged)>.18?damaged:dist(a,x)-dist(a,y)});return pool[0]}
function assignTarget(target,attacker){if(!target||!attacker||attacker.team!==game.playerTeam||!canOrder(attacker))return false;attacker.targetId=target.id;attacker.reactorOrder=false;attacker.holdingReactor=false;attacker.orderedUntil=Number.MAX_VALUE;game.manualTargetId=target.id;game.lastOrderFriendlyId=attacker.id;game.lastOrderTargetId=target.id;game.orderFriendlyId=null;game.orderEnemyId=null;game.orderReactor=false;setStatus(attacker.id+" focusing "+target.id,attacker.kind==="soldier"?"Soldier will fire while advancing and smash the target at close range.":"This tower will keep firing at the selected target.");addRing(attacker.x,attacker.z,"gold",.5);addRing(target.x,target.z,"red",.7);return true}
function spawnSoldier(t,announce=t.team===game.playerTeam){t.deployed=true;t.weaponReadyAt=Infinity;t.targetId=null;const spawnZ=game.world===3?t.z+(t.team===game.playerTeam?-2.5:2.5):t.z-2.5,s={id:(t.team==="blue"?"B-S":"R-S")+game.nextSoldier++,team:t.team,kind:"soldier",sourceTowerId:t.id,x:t.x,z:spawnZ,hp:C.soldierHp,maxHp:C.soldierHp,alive:true,targetId:null,reactorOrder:false,holdingReactor:false,nextFire:game.elapsed,nextSmash:game.elapsed,orderedUntil:0,hitFlash:0,shieldUntil:0};game.entities.push(s);if(announce){game.selectedId=s.id;game.deployArmedUntil=0;setStatus(s.id+" deployed",game.world===3?"Tap the central reactor to capture it, or tap an enemy tower.":t.id+"'s weapon is offline while its soldier is active.")}burst(t.x,spawnZ,t.team,16);addRing(t.x,t.z,t.team,.9);sound("start");updateHud();return s}
function handleDeploy(){const t=byId(game.selectedId);if(!t||t.team!==game.playerTeam||t.kind!=="tower"||!t.alive||t.deployed)return;spawnSoldier(t)}
function activateShield(team,targetId){const s=game.shields[team],target=byId(targetId);if(!target||!target.alive||target.team!==team||target.kind==="barrier"||target.kind==="reactor"){if(team===game.playerTeam)setStatus("Select a unit first","Select one of your towers or walking soldiers, then activate its shield.");return false}if(s.uses<=0||game.elapsed<s.activeUntil||game.elapsed<s.readyAt)return false;s.uses--;s.activeUntil=game.elapsed+C.shieldDuration;const reactorBonus=game.world===3&&game.reactor&&game.reactor.team===team?C.reactorShieldBonus:0;s.readyAt=s.activeUntil+C.shieldCooldown-reactorBonus;target.shieldUntil=s.activeUntil;addRing(target.x,target.z,team,1.2);if(team===game.playerTeam)setStatus(target.id+" shielded",reactorBonus?"Reactor power shortens this shield cooldown by three seconds.":"This unit blocks all incoming damage for five seconds.");sound("shield");updateHud();return true}
function shielded(target){return game.elapsed<(target.shieldUntil||0)}
function fire(a,t){const reactorRate=game.world===3&&game.reactor&&game.reactor.team===a.team&&a.kind==="tower"?C.reactorFireBoost:1,rate=(a.kind==="tower"?C.towerRate:C.soldierRate)*levels[game.difficulty].fireRate*reactorRate,damage=a.kind==="tower"?C.towerDamage:C.soldierDamage;a.nextFire=game.elapsed+rate;game.projectiles.push({id:game.nextShot++,sourceId:a.id,targetId:t.id,team:a.team,startX:a.x,startZ:a.z,startAt:game.elapsed,duration:Math.max(.22,dist(a,t)/C.shotSpeed),damage});burst(a.x,a.z,a.team,3);if(Math.random()<.35)sound("shoot")}
function hit(target,damage,team){if(!target.alive)return;const blocker=activeBarrierFor(target);if(blocker)return hit(blocker,damage,team);if(shielded(target)){addRing(target.x,target.z,target.team,.34);burst(target.x,target.z,target.team,5);return}target.hp=Math.max(0,target.hp-damage);target.hitFlash=.12;if(team===game.playerTeam)game.damageDealt+=damage;burst(target.x,target.z,target.team==="blue"?"red":"blue",7);sound("impact");if(target.hp<=0)destroy(target)}
function destroy(e){e.alive=false;e.targetId=null;const wasController=game.reactor&&game.reactor.controllerId===e.id;if(wasController){game.reactor.controllerId=null;game.reactor.team=null;game.reactor.captureFlash=1;addRing(game.reactor.x,game.reactor.z,"gold",1);if(e.team===game.playerTeam)setStatus("Reactor lost","Your controlling soldier was destroyed. The reactor is neutral again.");else setStatus("Reactor neutral","The enemy controller was destroyed. Send a soldier to capture it.")}game.cameraShake=e.kind==="barrier"?.7:e.kind==="tower"?.45:.18;burst(e.x,e.z,"fire",e.kind==="barrier"?48:e.kind==="tower"?36:14);addRing(e.x,e.z,"fire",.9);if(e.kind==="tower"||e.kind==="barrier")sound("explode");if(e.kind==="barrier"&&e.team!==game.playerTeam)setStatus(e.id+" breached","The towers behind this barrier are exposed.");if(e.kind==="soldier"&&e.sourceTowerId){const source=byId(e.sourceTowerId);if(source&&source.alive){source.rearmStartedAt=game.elapsed;source.weaponReadyAt=source.rearmStartedAt+3;source.nextFire=source.weaponReadyAt;if(!wasController)setStatus(e.id+" destroyed",source.id+" will resume firing in 3 seconds.")}}if(game.selectedId===e.id){game.selectedId=null;if(e.kind!=="soldier"||!e.sourceTowerId)setStatus("Unit destroyed","Select another tower or tap an enemy to redirect fire.")}for(const u of game.entities)if(u.targetId===e.id)u.targetId=null;updateHud()}
function updateCombat(dt){for(const u of game.entities){if(u.hitFlash>0)u.hitFlash-=dt;if(!u.alive||!canAttack(u))continue;let t=byId(u.targetId);if(!t||!t.alive||(t.team===u.team&&t.kind!=="reactor")){if(u.kind==="soldier"&&u.reactorOrder&&game.reactor)t=game.reactor;else{t=autoTarget(u);u.reactorOrder=false}u.targetId=t?t.id:null;u.orderedUntil=0}if(u.kind==="soldier"&&u.holdingReactor){if(!game.reactor||game.reactor.controllerId!==u.id){u.holdingReactor=false;u.reactorOrder=false}else{u.x=game.reactor.x+(u.team===game.playerTeam?-1.1:1.1);u.z=game.reactor.z+(u.team===game.playerTeam?1.1:-1.1);const enemyTeam=u.team==="blue"?"red":"blue",threat=living(enemyTeam,"soldier").sort((a,b)=>dist(u,a)-dist(u,b))[0];if(threat&&dist(u,threat)<=C.soldierRange&&game.elapsed>=u.nextFire)fire(u,threat);continue}}if(!t)continue;if(u.kind==="soldier"&&u.reactorOrder&&game.reactor){const controller=reactorController();if(controller&&controller.team!==u.team)t=controller;else if(!controller){const range=dist(u,game.reactor);if(range<=C.reactorCaptureRange){captureReactor(u);continue}const dx=game.reactor.x-u.x,dz=game.reactor.z-u.z,len=Math.max(.001,Math.hypot(dx,dz));u.x+=dx/len*C.soldierSpeed*dt;u.z+=dz/len*C.soldierSpeed*dt;continue}else{u.reactorOrder=false;t=autoTarget(u);u.targetId=t?t.id:null}}if(!t)continue;if(u.kind==="soldier"){const range=dist(u,t),canSmash=(t.kind==="tower"||t.kind==="barrier")&&range<=C.smashRange;if(canSmash){if(game.elapsed>=u.nextSmash){u.nextSmash=game.elapsed+C.smashRate;game.cameraShake=.38;addShockwave(t.x,t.z,u.team);burst(t.x,t.z,"fire",22);hit(t,C.smashDamage,u.team);sound("explode")}}else{if(range>C.smashRange){const dx=t.x-u.x,dz=t.z-u.z,len=Math.max(.001,Math.hypot(dx,dz));u.x+=dx/len*C.soldierSpeed*dt;u.z+=dz/len*C.soldierSpeed*dt}if(game.elapsed>=u.nextFire)fire(u,t)}}else if(game.elapsed>=u.nextFire)fire(u,t)}for(let i=game.projectiles.length-1;i>=0;i--){const s=game.projectiles[i];if(game.elapsed-s.startAt>=s.duration){const t=byId(s.targetId);if(t&&t.alive&&t.kind!=="reactor")hit(t,s.damage,s.team);game.projectiles.splice(i,1)}}}
function specialName(team){return team==="blue"?"Giant":"Megalodon"}
function specialUnlocked(team){return living(team,"tower").length<game.startingTowers}
function deploySpecial(team,targetId=null){const state=game.specials[team],target=targetId?byId(targetId):null;if(!state||state.used||!specialUnlocked(team))return false;if(targetId&&(!target||!target.alive||target.team===team||(target.kind!=="tower"&&target.kind!=="barrier")))return false;state.used=true;const start=game.world>=2?mapPosition(team===game.playerTeam?.10:.90,team===game.playerTeam?.90:.12):{x:team==="blue"?-12:14,z:team===game.playerTeam?34:-34},startZ=start.z,startX=start.x;game.specialUnits.push({team,targetId:target?target.id:null,phase:target?"approach":"choosing",x:startX,z:startZ,startX,startZ,progress:0,timer:0});if(team===game.playerTeam)setStatus(specialName(team)+" deployed",target?specialName(team)+" is heading for "+target.id+".":(game.world===2?"Tap the enemy barrier or exposed tower ":"Tap the enemy tower ")+specialName(team)+" should destroy.");sound("start");updateHud();return true}
function retargetSpecial(unit){const targets=structureTargets(unit.team===game.playerTeam?game.aiTeam:game.playerTeam);if(!targets.length)return null;targets.sort((a,b)=>dist(unit,a)-dist(unit,b));unit.targetId=targets[0].id;unit.phase="approach";unit.progress=0;unit.startX=unit.x;unit.startZ=unit.z;if(unit.team===game.playerTeam)setStatus(specialName(unit.team)+" retargeting","Original target lost. Switching to "+targets[0].id+".");return targets[0]}
function specialEdge(unit,target){const dx=unit.startX-target.x,dz=unit.startZ-target.z,len=Math.max(.001,Math.hypot(dx,dz));return{x:target.x+dx/len*4.4,z:target.z+dz/len*4.4}}
function updateSpecials(dt){for(let i=game.specialUnits.length-1;i>=0;i--){const u=game.specialUnits[i];if(u.phase==="choosing")continue;let target=byId(u.targetId);if((!target||!target.alive)&&u.phase!=="leaving")target=retargetSpecial(u);if(!target&&u.phase!=="leaving"){u.phase="leaving";u.timer=0}if(u.phase==="approach"&&target){const edge=specialEdge(u,target);u.progress=Math.min(1,u.progress+dt/C.specialApproach);const ease=1-Math.pow(1-u.progress,2);u.x=u.startX+(edge.x-u.startX)*ease;u.z=u.startZ+(edge.z-u.startZ)*ease;if(u.progress>=1){u.phase=shielded(target)?"waiting":"striking";u.timer=0}}else if(u.phase==="waiting"&&target){const edge=specialEdge(u,target);u.x=edge.x;u.z=edge.z;if(!shielded(target)){u.phase="striking";u.timer=0;if(u.team===game.playerTeam)setStatus(specialName(u.team)+" attacking",target.id+" shield dropped.");}}else if(u.phase==="striking"&&target){if(shielded(target)){u.phase="waiting";u.timer=0}else{u.timer+=dt;if(u.timer>=C.specialStrike){game.cameraShake=.8;burst(target.x,target.z,"fire",55);addRing(target.x,target.z,"fire",1.2);destroy(target);u.phase="leaving";u.timer=0;if(u.team===game.playerTeam)setStatus(target.id+" destroyed",specialName(u.team)+" completed its attack and is leaving.");sound("explode")}}}else if(u.phase==="leaving"){u.timer+=dt;u.z+=u.team===game.playerTeam?18*dt:-18*dt;u.x+=game.world>=2?(u.team===game.playerTeam?-10*dt:10*dt):(u.team==="blue"?-14*dt:14*dt);if(u.timer>=.7)game.specialUnits.splice(i,1)}}}
function updateAI(){if(game.elapsed<game.aiAt)return;const l=levels[game.difficulty],team=game.aiTeam;game.aiAt=game.elapsed+l.delay*(.85+Math.random()*.35);const special=game.specials[team];if(specialUnlocked(team)&&!special.used&&!game.specialUnits.some(u=>u.team===team)){const specialTarget=structureTargets(game.playerTeam).sort((a,b)=>b.hp-a.hp)[0];if(specialTarget)deploySpecial(team,specialTarget.id)}if(game.elapsed>=game.aiDeployAt){const towers=living(team,"tower").filter(t=>!t.deployed);if(towers.length){const soldier=spawnSoldier(towers[Math.floor(Math.random()*towers.length)],false),chance=game.difficulty==="hard"?.9:game.difficulty==="medium"?.65:.15;if(game.world===3&&game.reactor&&game.reactor.team!==team&&Math.random()<chance)sendToReactor(soldier,false);game.aiDeployAt=game.elapsed+aiDeployDelay()}else game.aiDeployAt=Infinity}if(game.world===3&&game.reactor&&game.reactor.team!==team){const chance=game.difficulty==="hard"?.42:game.difficulty==="medium"?.2:.03,candidate=living(team,"soldier").find(u=>!u.holdingReactor&&!u.reactorOrder);if(candidate&&Math.random()<chance)sendToReactor(candidate,false)}const s=game.shields[team];if(s.uses<=0||game.elapsed<s.readyAt)return;const threatened=game.projectiles.map(p=>byId(p.targetId)).find(t=>t&&t.alive&&t.team===team),endangered=living(team,"tower").find(t=>t.hp<=48),target=endangered||threatened;if(target&&Math.random()<l.shield)activateShield(team,target.id)}
function reactorController(){if(!game.reactor||!game.reactor.controllerId)return null;const controller=byId(game.reactor.controllerId);if(!controller||!controller.alive){game.reactor.controllerId=null;game.reactor.team=null;return null}return controller}
function sendToReactor(soldier,announce=true){if(game.world!==3||!game.reactor||!soldier||!soldier.alive||soldier.kind!=="soldier")return false;soldier.targetId=game.reactor.id;soldier.reactorOrder=true;soldier.holdingReactor=false;soldier.orderedUntil=Number.MAX_VALUE;if(announce){game.selectedId=soldier.id;game.manualTargetId=null;game.lastOrderFriendlyId=soldier.id;game.lastOrderTargetId=game.reactor.id;game.orderFriendlyId=null;game.orderEnemyId=null;game.orderReactor=false;setStatus(soldier.id+" capturing reactor","The soldier will remain at the reactor and control it until destroyed.");addRing(soldier.x,soldier.z,"gold",.5);addRing(game.reactor.x,game.reactor.z,"gold",.8)}return true}
function captureReactor(soldier){if(!game.reactor||!soldier.alive)return false;const controller=reactorController();if(controller&&controller.team!==soldier.team)return false;game.reactor.team=soldier.team;game.reactor.controllerId=soldier.id;game.reactor.captureFlash=1;soldier.holdingReactor=true;soldier.reactorOrder=true;soldier.targetId=game.reactor.id;soldier.x=game.reactor.x+(soldier.team===game.playerTeam?-1.1:1.1);soldier.z=game.reactor.z+(soldier.team===game.playerTeam?1.1:-1.1);addShockwave(game.reactor.x,game.reactor.z,soldier.team);burst(game.reactor.x,game.reactor.z,soldier.team,28);sound("shield");if(soldier.team===game.playerTeam)setStatus("Reactor captured","Your towers fire 25% faster and shields recharge three seconds sooner.");else setStatus("Enemy controls reactor","Destroy the soldier at the reactor to remove the enemy power bonus.");return true}
function updateStorm(){const storm=game.storm;if(game.world!==3||!storm)return;if(storm.phase==="idle"&&game.elapsed>=storm.nextAt){let lane=Math.floor(Math.random()*STORM_LANES.length);if(lane===storm.lastLane)lane=(lane+1+Math.floor(Math.random()*2))%STORM_LANES.length;storm.lane=lane;storm.lastLane=lane;storm.phase="warning";storm.until=game.elapsed+C.stormWarning;storm.nextAt+=C.stormInterval;setStatus(STORM_LANES[lane].name+" lane warning","Electrical storm arriving in three seconds. Towers in that lane will stop firing.")}else if(storm.phase==="warning"&&game.elapsed>=storm.until){storm.phase="active";storm.until=game.elapsed+C.stormActive;game.cameraShake=.25;sound("shield")}else if(storm.phase==="active"&&game.elapsed>=storm.until){storm.phase="idle";storm.lane=-1}}
function checkEnd(){if(!living(game.aiTeam,"tower").length)return endMatch("victory");if(!living(game.playerTeam,"tower").length)return endMatch("defeat")}
function addRing(x,z,color,life){game.rings.push({x,z,color,life,maxLife:life})}
function addShockwave(x,z,color){game.rings.push({x,z,color,life:.72,maxLife:.72,shockwave:true})}
function burst(x,z,color,count){for(let i=0;i<count;i++)game.particles.push({x,z,height:3+Math.random()*10,vx:(Math.random()-.5)*8,vz:(Math.random()-.5)*8,vh:5+Math.random()*13,life:.35+Math.random()*.65,maxLife:1,color,size:1.5+Math.random()*3.5})}
function updateRearming(){for(const t of game.entities){if(t.kind!=="tower"||!t.alive||!Number.isFinite(t.weaponReadyAt)||t.weaponReadyAt<=0||game.elapsed<t.weaponReadyAt)continue;t.weaponReadyAt=0;t.nextFire=game.elapsed;addRing(t.x,t.z,t.team,.75);if(t.team===game.playerTeam)setStatus(t.id+" rearmed","Tower weapon is firing again.")}}
function updateEffects(dt){for(const b of game.barriers)if(b.hitFlash>0)b.hitFlash-=dt;if(game.reactor&&game.reactor.captureFlash>0)game.reactor.captureFlash=Math.max(0,game.reactor.captureFlash-dt);for(let i=game.particles.length-1;i>=0;i--){const p=game.particles[i];p.x+=p.vx*dt;p.z+=p.vz*dt;p.height+=p.vh*dt;p.vh-=20*dt;p.life-=dt;if(p.life<=0)game.particles.splice(i,1)}for(let i=game.rings.length-1;i>=0;i--){game.rings[i].life-=dt;if(game.rings[i].life<=0)game.rings.splice(i,1)}game.cameraShake=Math.max(0,game.cameraShake-dt*1.8)}
function update(dt){game.elapsed+=dt;if(game.elapsed>game.deployArmedUntil&&ui.deploy.classList.contains("armed")){game.deployArmedUntil=0;ui.deploy.classList.remove("armed");ui.deploy.textContent="Deploy Soldier"}updateStorm();updateRearming();updateCombat(dt);updateSpecials(dt);updateAI();updateEffects(dt);updateHud();checkEnd()}

function resizeCanvas(){const r=canvas.getBoundingClientRect(),d=Math.min(window.devicePixelRatio||1,1.5);viewport={w:r.width,h:r.height,dpr:d};canvas.width=Math.max(1,Math.floor(r.width*d));canvas.height=Math.max(1,Math.floor(r.height*d));ctx.setTransform(d,0,0,d,0,0)}
function size(){return viewport}
function project(x,z,height=0){const s=size();if(game.world>=2){const nx=x/C.worldWidth+.5,ny=z/C.worldDepth+.5,scale=.55+ny;return{x:nx*s.w,y:ny*s.h-height*scale*Math.min(s.w,s.h)/620,scale}}const horizon=s.h*.265,t=(z+C.worldDepth/2)/C.worldDepth,scale=.44+t*1.02,field=Math.min(s.w*.88,s.h*1.55);return{x:s.w/2+x*scale*field/C.worldWidth,y:horizon+t*s.h*.62-height*scale*Math.min(s.w,s.h)/620,scale}}
function drawBackground(now){const s=size(),w=s.w,h=s.h,img=game.world===3?art.stormBackground:game.world===2?art.riftBackground:art.background;if(img.complete&&img.naturalWidth){if(game.world>=2)ctx.drawImage(img,0,0,w,h);else{const scale=Math.max(w/img.naturalWidth,h/img.naturalHeight),dw=img.naturalWidth*scale,dh=img.naturalHeight*scale;ctx.drawImage(img,(w-dw)/2,(h-dh)/2,dw,dh)}const shade=ctx.createLinearGradient(0,0,0,h);shade.addColorStop(0,"rgba(13,24,37,.03)");shade.addColorStop(.6,"rgba(20,12,20,0)");shade.addColorStop(1,"rgba(8,8,14,.28)");ctx.fillStyle=shade;ctx.fillRect(0,0,w,h);return}const horizon=h*.265,sky=ctx.createLinearGradient(0,0,0,horizon);sky.addColorStop(0,"#489ed4");sky.addColorStop(.7,"#86c8ec");sky.addColorStop(1,"#d0e9ef");ctx.fillStyle=sky;ctx.fillRect(0,0,w,horizon+1);ctx.fillStyle="#7b392f";ctx.fillRect(0,horizon,w,h-horizon);drawGrid();drawCrystals(now)}
function drawMountains(w,h){const layers=[["rgba(66,58,80,.42)",[0,.13,.21,.34,.46,.59,.73,.86,1]],["rgba(72,46,62,.68)",[0,.16,.29,.43,.55,.68,.82,1]]];for(const layer of layers){ctx.fillStyle=layer[0];ctx.beginPath();ctx.moveTo(0,h);layer[1].forEach((p,i)=>ctx.lineTo(p*w,i%2?h-(35+i%3*20):h-h*.06));ctx.lineTo(w,h);ctx.closePath();ctx.fill()}}
function drawGrid(){ctx.save();ctx.strokeStyle="rgba(255,205,137,.12)";ctx.lineWidth=1;for(let z=-32;z<=34;z+=7){const a=project(-23,z),b=project(23,z);ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke()}for(let x=-20;x<=20;x+=5){const a=project(x,-33),b=project(x,35);ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke()}ctx.restore()}
function drawCrystals(now){const list=[[-19,-4,5,"#9b6fff"],[20,3,7,"#59d5ff"],[-22,24,9,"#8d70ff"],[22,-23,5,"#50c7eb"],[18,29,6,"#b784ff"],[-20,-27,4,"#72d7f4"]];for(const c of list){const b=project(c[0],c[1]),t=project(c[0],c[1],c[2]);ctx.save();ctx.globalAlpha=.72+Math.sin(now*.002+c[0])*.18;ctx.fillStyle=c[3];ctx.beginPath();ctx.moveTo(b.x-3*b.scale,b.y);ctx.lineTo(t.x,t.y);ctx.lineTo(b.x+4*b.scale,b.y);ctx.closePath();ctx.fill();ctx.restore()}}
function color(team){return team==="blue"?"#35c8ff":team==="red"?"#ff554e":team==="gold"?"#ffd56a":"#ffb24d"}
function barrierGeometry(b){const p=project(b.x,b.z),w=b.mapWidth*size().w,h=Math.max(70,w*.36);return{p,w,h}}
function barrierFrame(b,g){const c=Math.cos(b.angle),s=Math.sin(b.angle),half=g.w*.47;return{c,s,panelHeight:g.h*.58,postHeight:g.h*.82,left:{x:g.p.x-c*half,y:g.p.y-s*half},right:{x:g.p.x+c*half,y:g.p.y+s*half}}}
function barrierPalette(team){return team==="blue"?{energy:"#35c8ff",edge:"#9aecff",metal:"#173641",dark:"#081820",fillTop:"rgba(129,232,255,.15)",fillBottom:"rgba(32,177,236,.42)"}:{energy:"#ff5b55",edge:"#ffc0b7",metal:"#482326",dark:"#1d0b0d",fillTop:"rgba(255,173,159,.14)",fillBottom:"rgba(238,66,65,.4)"}}
