function updateHud(){ui.blueTowers.textContent=living("blue","tower").length;ui.redTowers.textContent=living("red","tower").length;ui.matchTime.textContent=formatTime(game.elapsed);ui.matchStatus.textContent=game.world===3?(game.storm&&game.storm.phase!=="idle"?STORM_LANES[game.storm.lane].name+" "+(game.storm.phase==="warning"?"ALERT":"STORM"):"STORM "+game.worldBattle):game.world===2?"RIFT "+game.worldBattle:"BATTLE "+game.level;const t=byId(game.selectedId),selected=t&&t.alive&&t.team===game.playerTeam,valid=selected&&t.kind==="tower"&&!t.deployed;ui.deploy.disabled=!valid||game.phase!=="playing";if(!valid){game.deployArmedUntil=0;ui.deploy.classList.remove("armed");ui.deploy.textContent="Deploy Soldier"}const s=game.shields[game.playerTeam],active=game.elapsed<s.activeUntil,cooling=!active&&game.elapsed<s.readyAt;ui.shield.disabled=game.phase!=="playing"||!selected||active||cooling||s.uses<=0;ui.shield.classList.toggle("shield-ready",selected&&!active&&!cooling&&s.uses>0);ui.shield.classList.toggle("shield-active",active);ui.shield.textContent=active?"Shield "+Math.ceil(s.activeUntil-game.elapsed)+"s":cooling?"Ready "+Math.ceil(s.readyAt-game.elapsed)+"s":selected?"Shield "+t.id+" ("+s.uses+")":"Select for Shield";const special=game.specials[game.playerTeam],name=specialName(game.playerTeam),unlocked=specialUnlocked(game.playerTeam),specialActive=game.specialUnits.some(u=>u.team===game.playerTeam),target=byId(game.manualTargetId),validTarget=target&&target.alive&&target.team===game.aiTeam&&target.kind==="tower";ui.special.classList.toggle("special-ready",unlocked&&!special.used);ui.special.classList.toggle("special-active",specialActive);ui.special.disabled=game.phase!=="playing"||special.used||!unlocked;ui.special.textContent=special.used?(specialActive?name+" Active":name+" Used"):!unlocked?name+" Locked":"Deploy "+name;ui.debugUnits.textContent="Units "+living().length;ui.debugProjectiles.textContent="Shots "+game.projectiles.length;ui.debugDamage.textContent="Damage "+Math.round(game.damageDealt)}
function positionSlot(u){return[+(u.x/C.worldWidth+.5).toFixed(4),+(u.z/C.worldDepth+.5).toFixed(4)]}
function collectRiftLayout(){const slots={},barriers={};for(const group of RIFT_GROUPS){slots[group]=game.entities.filter(u=>u.kind==="tower"&&u.riftGroup===group).map(positionSlot);const b=game.barriers.find(item=>item.group===group),p=positionSlot(b);barriers[group]={nx:p[0],ny:p[1],width:+b.mapWidth.toFixed(4),angle:+b.angle.toFixed(4)}}return{slots,barriers}}
function collectStormLayout(){const lanes=STORM_LANES.map((lane,index)=>({name:lane.name,near:game.entities.filter(u=>u.kind==="tower"&&u.lane===index&&u.team===game.playerTeam).map(positionSlot),far:game.entities.filter(u=>u.kind==="tower"&&u.lane===index&&u.team===game.aiTeam).map(positionSlot)})),reactor=positionSlot(game.reactor);return{lanes,reactor}}
function saveRiftLayout(){const data=collectRiftLayout();if(!validRiftLayout(data))return null;activeRiftLayout=data;RIFT_SLOTS=data.slots;RIFT_BARRIER_SPECS=data.barriers;try{localStorage.setItem("towerBattleRiftLayout",JSON.stringify(data))}catch{}return data}
function saveStormLayout(){const data=collectStormLayout();if(!validStormLayout(data))return null;activeStormLayout=data;STORM_LANES=data.lanes;STORM_REACTOR=data.reactor;try{localStorage.setItem("towerBattleStormLayout",JSON.stringify(data))}catch{}return data}
function saveCurrentLayout(){return game.world===2?saveRiftLayout():saveStormLayout()}
function resetRiftLayout(){try{localStorage.removeItem("towerBattleRiftLayout")}catch{}activeRiftLayout=freshRiftLayout();RIFT_SLOTS=activeRiftLayout.slots;RIFT_BARRIER_SPECS=activeRiftLayout.barriers;startRiftLayoutEditor();ui.layoutMessage.textContent="Default positions restored. Drag anything to move it."}
function resetStormLayout(){try{localStorage.removeItem("towerBattleStormLayout")}catch{}activeStormLayout=freshStormLayout();STORM_LANES=activeStormLayout.lanes;STORM_REACTOR=activeStormLayout.reactor;startStormLayoutEditor();ui.layoutMessage.textContent="Default positions restored. Drag anything to move it."}
function resetCurrentLayout(){game.world===2?resetRiftLayout():resetStormLayout()}
async function copyCurrentLayout(){const data=saveCurrentLayout();if(!data)return;const text=JSON.stringify(data,null,2);try{await navigator.clipboard.writeText(text)}catch{const field=document.createElement("textarea");field.value=text;field.style.position="fixed";field.style.opacity="0";document.body.appendChild(field);field.select();document.execCommand("copy");field.remove()}ui.layoutMessage.textContent="Layout copied. Paste it into your Codex message."}
function testCurrentLayout(){saveCurrentLayout();game.worldBattle=1;game.lastResult=null;prepareMatch()}
function layoutAnchor(u){return u.kind==="reactor"?reactorScreenPoint():project(u.x,u.z)}
function layoutItemName(u){return u.kind==="reactor"?"Reactor":u.kind==="barrier"?"Shield "+u.id:u.id}
function rotationTargetAt(pt){if(game.world!==2)return null;const b=byId(game.manualTargetId);if(!b||b.kind!=="barrier")return null;const h=barrierRotationHandle(b);return Math.hypot(pt.x-h.x,pt.y-h.y)<=h.hitRadius?b:null}
function startLayoutDrag(e){e.preventDefault();const pt=point(e),rotating=rotationTargetAt(pt);if(rotating){game.layoutDrag={id:rotating.id,pointerId:e.pointerId,mode:"rotate"};ui.layoutMessage.textContent="Rotating "+layoutItemName(rotating);if(canvas.setPointerCapture)canvas.setPointerCapture(e.pointerId);return}const u=hitTest(pt);if(!u||(u.kind!=="tower"&&u.kind!=="barrier"&&u.kind!=="reactor"))return;const anchor=layoutAnchor(u);game.layoutDrag={id:u.id,pointerId:e.pointerId,mode:"move",offsetX:anchor.x-pt.x,offsetY:anchor.y-pt.y};game.selectedId=u.kind==="tower"?u.id:null;game.manualTargetId=u.kind==="barrier"?u.id:null;game.orderReactor=u.kind==="reactor";ui.layoutMessage.textContent="Moving "+layoutItemName(u);if(canvas.setPointerCapture)canvas.setPointerCapture(e.pointerId)}
function moveLayoutDrag(e){const drag=game.layoutDrag;if(game.phase!=="layout"||!drag||drag.pointerId!==e.pointerId)return;e.preventDefault();const u=byId(drag.id),pt=point(e);if(drag.mode==="rotate"){const center=project(u.x,u.z);u.angle=Math.atan2(pt.y-center.y,pt.x-center.x);return}const s=size(),screenX=pt.x+drag.offsetX,screenY=pt.y+drag.offsetY,nx=Math.max(.025,Math.min(.975,screenX/s.w)),ny=u.kind==="reactor"?Math.max(.04,Math.min(.96,(screenY+13*.55)/Math.max(1,s.h-13))):Math.max(.04,Math.min(.96,screenY/s.h)),p=mapPosition(nx,ny);u.x=p.x;u.z=p.z}
function finishLayoutDrag(e){const drag=game.layoutDrag;if(!drag||drag.pointerId!==e.pointerId)return;const u=byId(drag.id),action=drag.mode==="rotate"?" rotated":" placed";game.layoutDrag=null;saveCurrentLayout();ui.layoutMessage.textContent=(u?layoutItemName(u):"Position")+action+". Drag another item or test the battle.";if(canvas.releasePointerCapture&&canvas.hasPointerCapture&&canvas.hasPointerCapture(e.pointerId))canvas.releasePointerCapture(e.pointerId)}
function point(e){const r=canvas.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top}}
function hitTest(pt){const hits=[];if(game.world===3&&game.reactor){const p=reactorScreenPoint(),rx=Math.max(48,Math.min(size().w,size().h)*.075),ry=rx*.55;if(Math.abs(pt.x-p.x)<=rx&&Math.abs(pt.y-p.y)<=ry)hits.push({u:game.reactor,score:Math.hypot((pt.x-p.x)/rx,(pt.y-p.y)/ry),z:game.reactor.z})}if(game.world===2)for(const u of game.barriers){if(!u.alive)continue;const g=barrierGeometry(u),dx=pt.x-g.p.x,dy=pt.y-g.p.y,c=Math.cos(u.angle),sn=Math.sin(u.angle),lx=dx/(Math.abs(c)<.15?(c<0?-.15:.15):c),ly=dy-sn*lx;if(Math.abs(lx)<=g.w*.52&&ly>=-g.h*.9&&ly<=g.h*.22)hits.push({u,score:Math.hypot(lx/g.w,ly/g.h),z:u.z})}for(const u of game.entities){if(!u.alive)continue;const base=project(u.x,u.z),s=base.scale;if(u.kind==="tower"){const worldScale=game.world===3?.72:1,width=Math.max(58,116*s*.8*worldScale),height=Math.max(76,116*s*1.08*worldScale),cx=base.x,cy=base.y-height*.46;if(Math.abs(pt.x-cx)<=width/2&&Math.abs(pt.y-cy)<=height/2)hits.push({u,score:Math.hypot((pt.x-cx)/width,(pt.y-cy)/height),z:u.z})}else{const head=project(u.x,u.z,10),width=Math.max(50,34*s),top=head.y-22,bottom=base.y+20;if(pt.x>=base.x-width/2&&pt.x<=base.x+width/2&&pt.y>=top&&pt.y<=bottom)hits.push({u,score:Math.abs(pt.x-base.x)/width,z:u.z})}}hits.sort((a,b)=>a.score-b.score||b.z-a.z);return hits.length?hits[0].u:null}
function handlePointer(e){if(game.phase==="layout")return startLayoutDrag(e);if(game.phase!=="playing")return;e.preventDefault();ensureAudio();let u=hitTest(point(e));if(!u){game.selectedId=null;game.manualTargetId=null;game.orderFriendlyId=null;game.orderEnemyId=null;game.orderReactor=false;setStatus("No unit selected",game.world===3?"Tap a soldier and the central reactor in either order, or focus fire on an enemy tower.":game.world===2?"Tap a barrier or exposed enemy tower, then one of your units.":"Tap one of your units and one enemy target, in either order.")}else if(u.kind==="reactor"){const soldier=byId(game.orderFriendlyId)||byId(game.selectedId);if(soldier&&soldier.alive&&soldier.team===game.playerTeam&&soldier.kind==="soldier")sendToReactor(soldier);else{game.orderReactor=true;game.orderEnemyId=null;game.manualTargetId=null;setStatus(u.team?u.team.toUpperCase()+" controls reactor":"Neutral reactor","Now tap one of your walking soldiers to capture it.");addRing(u.x,u.z,"gold",.8)}}else if(u.team===game.playerTeam){if(u.kind==="barrier"){game.selectedId=null;game.orderFriendlyId=null;setStatus(u.id+" barrier",Math.ceil(u.hp)+" barrier strength remaining.")}else if(game.orderReactor&&u.kind==="soldier"){sendToReactor(u)}else{game.orderReactor=false;game.selectedId=u.id;const enemy=byId(game.orderEnemyId);if(enemy&&enemy.alive)assignTarget(enemy,u);else{game.orderFriendlyId=u.id;game.orderEnemyId=null;if(u.kind==="tower")setStatus(u.id+" selected",u.deployed?"Tap an enemy target, or shield this structure.":"Tap an enemy target, deploy its soldier, or shield it.");else setStatus(u.id+" selected",game.world===3?"Tap the reactor to capture it, or tap an enemy tower.":"Tap an enemy barrier or tower for this soldier to pursue.");addRing(u.x,u.z,"gold",.45)}}}else{game.orderReactor=false;u=attackableTarget(u);const waiting=game.specialUnits.find(s=>s.team===game.playerTeam&&s.phase==="choosing");if(waiting&&(u.kind==="tower"||u.kind==="barrier")){waiting.targetId=u.id;waiting.phase="approach";waiting.progress=0;waiting.startX=waiting.x;waiting.startZ=waiting.z;game.manualTargetId=u.id;setStatus(specialName(game.playerTeam)+" targeting "+u.id,"Special attack is underway.");addRing(u.x,u.z,"red",.8)}else{const friendly=byId(game.orderFriendlyId);if(friendly&&friendly.alive&&canOrder(friendly))assignTarget(u,friendly);else{game.orderEnemyId=u.id;game.orderFriendlyId=null;game.manualTargetId=u.id;setStatus(u.id+" selected",u.kind==="barrier"?"Now tap one of your armed towers or walking soldiers to breach it.":"Now tap one of your armed towers or walking soldiers.");addRing(u.x,u.z,"red",.7)}}}updateHud()}
for(const b of document.querySelectorAll(".team-choice"))b.addEventListener("click",()=>{game.playerTeam=b.dataset.team;for(const p of document.querySelectorAll(".team-choice"))p.classList.toggle("selected",p===b);resetMatch()});
for(const b of document.querySelectorAll(".difficulty"))b.addEventListener("click",()=>{game.difficulty=b.dataset.difficulty;for(const p of document.querySelectorAll(".difficulty"))p.classList.toggle("selected",p===b)});
ui.start.addEventListener("click",startMatch);
ui.testLock.addEventListener("click",toggleTestingControls);
ui.stageStart.addEventListener("click",startMatch);
ui.level2.addEventListener("click",startLevel2);
ui.level3.addEventListener("click",startLevel3);
$("level-4-button").addEventListener("click",()=>{location.href="level4.html?team="+game.playerTeam+"&difficulty="+game.difficulty});
ui.layout2.addEventListener("click",startRiftLayoutEditor);
ui.layout3.addEventListener("click",startStormLayoutEditor);
ui.layoutReset.addEventListener("click",resetCurrentLayout);
ui.layoutCopy.addEventListener("click",copyCurrentLayout);
ui.layoutTest.addEventListener("click",testCurrentLayout);
ui.layoutMenu.addEventListener("click",showMainMenu);
ui.restart.addEventListener("click",continueBattle);
ui.pause.addEventListener("click",pauseGame);
ui.resume.addEventListener("click",resumeGame);
ui.deploy.addEventListener("click",handleDeploy);
ui.shield.addEventListener("click",()=>activateShield(game.playerTeam,game.selectedId));
ui.special.addEventListener("click",()=>deploySpecial(game.playerTeam));
for(const b of document.querySelectorAll(".menu-button"))b.addEventListener("click",showMainMenu);
canvas.addEventListener("pointerdown",handlePointer,{passive:false});
canvas.addEventListener("pointermove",moveLayoutDrag,{passive:false});
canvas.addEventListener("pointerup",finishLayoutDrag);
canvas.addEventListener("pointercancel",finishLayoutDrag);
window.addEventListener("resize",resizeCanvas);
if(window.visualViewport)window.visualViewport.addEventListener("resize",resizeCanvas);
window.addEventListener("keydown",e=>{if(e.key==="Escape"){if(game.phase==="playing")pauseGame();else if(game.phase==="paused")resumeGame();else if(game.phase==="layout")showMainMenu()}if(e.code==="Space"&&game.phase==="playing"){e.preventDefault();activateShield(game.playerTeam,game.selectedId)}if(e.key.toLowerCase()==="d")ui.debugPanel.classList.toggle("hidden")});
resetMatch();setTestingUnlocked(false);resizeCanvas();requestAnimationFrame(render);
